mapper.select:
${pagingTop}
	SELECT
		HOMEPAGE_ID, QUICK_IDX, MENU_NAME, LINK_URL, LINK_TARGET, ICON_FILE_NAME, REAL_FILE_NAME, FILE_EXTENSION, FILE_SIZE, VIEW_YN, LINK_USE_YN, PRINT_SEQ, TO_CHAR(ADD_DATE, 'yyyy-mm-dd') AS ADD_DATE
	FROM
		CMS_QUICK_MENU
	WHERE HOMEPAGE_ID = #{homepage_id}

		AND	${search_type} LIKE '%'||#{search_text}||'%'

	ORDER BY
		PRINT_SEQ ASC
${pagingBottom}

SELECT COUNT(*) FROM CMS_QUICK_MENU WHERE HOMEPAGE_ID = #{homepage_id}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY QUICK_IDX ASC

mapper.insert:

	SELECT NVL(MAX(QUICK_IDX),0)+1 FROM CMS_QUICK_MENU WHERE HOMEPAGE_ID = #{homepage_id}


INSERT INTO CMS_QUICK_MENU
(
	HOMEPAGE_ID, QUICK_IDX, MENU_NAME, LINK_URL, LINK_TARGET, ICON_FILE_NAME, REAL_FILE_NAME, FILE_EXTENSION, FILE_SIZE, VIEW_YN, LINK_USE_YN, PRINT_SEQ, ADD_DATE
) VALUES (
	#{homepage_id}, #{quick_idx}, #{menu_name}, #{link_url}, #{link_target}, #{icon_file_name}, #{real_file_name}, #{file_extension}, #{file_size}, #{view_yn}, #{link_use_yn}, #{print_seq}, SYSDATE
)

mapper.update:
UPDATE CMS_QUICK_MENU SET MENU_NAME = #{menu_name}, LINK_URL = #{link_url}, LINK_TARGET = #{link_target},
ICON_FILE_NAME = #{icon_file_name}, REAL_FILE_NAME = #{real_file_name}, FILE_EXTENSION = #{file_extension}, FILE_SIZE = #{file_size},
VIEW_YN = #{view_yn}, LINK_USE_YN = #{link_use_yn}, PRINT_SEQ = #{print_seq} WHERE HOMEPAGE_ID = #{homepage_id} AND QUICK_IDX = #{quick_idx}

mapper.delete:
DELETE FROM CMS_QUICK_MENU
WHERE
	HOMEPAGE_ID = #{homepage_id} AND QUICK_IDX = #{quick_idx}
